@startuml
skinparam classAttributeIconSize 0

package UI {
  class RegisterPharmacyUI {
  }
}

package Controller {
  class RegisterPharmacyController {
    +newPharmacy(managerName,email,password, nif, name,latitude,longitude,\nstreetName,doorNumber,postalCode,locality,country)
    +registerPharmacy()
  }
}

package Data {
  class DataHandler {
    +openConnection()
    +closeAll()
  }
  class PharmacyDB {
    +PharmacyDB()
    +registerPharmacy()
  }
}

package Model {
  package Service {
    class PharmacyService {
      +PharmacyService()
      +addPharmacy(name, pharmacyManager,latitude,longitude,\nstreetName,doorNumber,postalCode,locality,country)
      +registerPharmacy()
    }
  }

  class Pharmacy {
    -int id
    -String name
    -String email
  }

  class Address {
    -String streetName
    -String doorNumber
    -String postalCode
    -String locality
    -String country
    -float longitude
    -float latitude
  }

  class ScooterPark {
    -int maxSlotsNumber
  }

  class DronePark {
    -int maxSlotsNumber
  }

  class ScooterChargingSlot {
    -int id
    -float outputPower
  }

  class ScooterParkingSlot {
    -int id
  }

  class DroneChargingSlot {
    -int id
    -float outputPower
  }

  class DroneParkingSlot {
    -int id
  }
}

class DataHandler_top as "DataHandler" {
}

class PharmacyDB_top as "PharmacyDB" {
}

database Database {
}

